-- cosmos.upgrade.v1beta1.Plan → cosmos_upgrade_plan_history (first appearance)
CREATE TABLE IF NOT EXISTS cosmos_upgrade_plan_history (
  name TEXT NULL,
  time JSONB NULL,
  height BIGINT NULL,
  info TEXT NULL,
  upgraded_client_state JSONB NULL,
  block_height BIGINT NOT NULL,
  block_time TIMESTAMPTZ NOT NULL,
  decoded_by_version SMALLINT NOT NULL,
  indexed_at TIMESTAMPTZ NOT NULL DEFAULT now(),
