  CONSTRAINT cosmos_upgrade_plan_history_decoder_fk FOREIGN KEY (decoded_by_version) REFERENCES decoder_version(id)
);
COMMENT ON COLUMN cosmos_upgrade_plan_history.name IS 'Sets the name for the upgrade. This name will be used by the upgraded version of the software to apply any special "on-upgrade" commands during the first BeginBlock method after the upgrade is applied. It is also used to detect whether a software version can handle a given upgrade. If no upgrade handler with this name has been set in the software, it will be assumed that the software is out-of-date when the upgrade Time or Height is reached and the software will exit.';
COMMENT ON COLUMN cosmos_upgrade_plan_history.time IS 'Deprecated: Time based upgrades have been deprecated. Time based upgrade logic has been removed from the SDK. If this field is not empty, an error will be thrown.';
COMMENT ON COLUMN cosmos_upgrade_plan_history.height IS 'The height at which the upgrade must be performed.';
COMMENT ON COLUMN cosmos_upgrade_plan_history.info IS 'Any application specific upgrade info to be included on-chain such as a git commit that validators could automatically upgrade to';
COMMENT ON COLUMN cosmos_upgrade_plan_history.upgraded_client_state IS 'Deprecated: UpgradedClientState field has been deprecated. IBC upgrade logic has been moved to the IBC module in the sub module 02-client. If this field is not empty, an error will be thrown.';

