  CONSTRAINT cosmos_slashing_validator_signing_info_history_decoder_fk FOREIGN KEY (decoded_by_version) REFERENCES decoder_version(id)
);
CREATE INDEX IF NOT EXISTS cosmos_slashing_validator_signing_info_history_current_idx ON cosmos_slashing_validator_signing_info_history (address, block_height DESC);
COMMENT ON COLUMN cosmos_slashing_validator_signing_info_history.start_height IS 'Height at which validator was first a candidate OR was un-jailed';
COMMENT ON COLUMN cosmos_slashing_validator_signing_info_history.index_offset IS 'Index which is incremented every time a validator is bonded in a block and _may_ have signed a pre-commit or not. This in conjunction with the signed_blocks_window param determines the index in the missed block bitmap.';
COMMENT ON COLUMN cosmos_slashing_validator_signing_info_history.jailed_until IS 'Timestamp until which the validator is jailed due to liveness downtime.';
COMMENT ON COLUMN cosmos_slashing_validator_signing_info_history.tombstoned IS 'Whether or not a validator has been tombstoned (killed out of validator set). It is set once the validator commits an equivocation or for any other configured misbehavior.';
COMMENT ON COLUMN cosmos_slashing_validator_signing_info_history.missed_blocks_counter IS 'A counter of missed (unsigned) blocks. It is used to avoid unnecessary reads in the missed block bitmap.';

