  quorum TEXT NULL,
  threshold TEXT NULL,
  veto_threshold TEXT NULL,
  min_initial_deposit_ratio TEXT NULL,
  proposal_cancel_ratio TEXT NULL,
  proposal_cancel_dest TEXT NULL,
  expedited_voting_period JSONB NULL,
  expedited_threshold TEXT NULL,
  expedited_min_deposit_amount BIGINT NULL,
  expedited_min_deposit_denom TEXT NULL,
  burn_vote_quorum BOOLEAN NULL,
  burn_proposal_deposit_prevote BOOLEAN NULL,
  burn_vote_veto BOOLEAN NULL,
  min_deposit_ratio TEXT NULL,
  block_height BIGINT NOT NULL,
  block_time TIMESTAMPTZ NOT NULL,
  decoded_by_version SMALLINT NOT NULL,
  indexed_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  CONSTRAINT cosmos_gov_params_history_pk PRIMARY KEY (block_height),
  CONSTRAINT cosmos_gov_params_history_decoder_fk FOREIGN KEY (decoded_by_version) REFERENCES decoder_version(id)
);
COMMENT ON COLUMN cosmos_gov_params_history.min_deposit_amount IS 'Minimum deposit for a proposal to enter voting period.';
COMMENT ON COLUMN cosmos_gov_params_history.min_deposit_denom IS 'Minimum deposit for a proposal to enter voting period.';
COMMENT ON COLUMN cosmos_gov_params_history.max_deposit_period IS 'Maximum period for Atom holders to deposit on a proposal. Initial value: 2 months.';
COMMENT ON COLUMN cosmos_gov_params_history.voting_period IS 'Duration of the voting period.';
COMMENT ON COLUMN cosmos_gov_params_history.quorum IS 'Minimum percentage of total stake needed to vote for a result to be considered valid.';
COMMENT ON COLUMN cosmos_gov_params_history.threshold IS 'Minimum proportion of Yes votes for proposal to pass. Default value: 0.5.';
COMMENT ON COLUMN cosmos_gov_params_history.veto_threshold IS 'Minimum value of Veto votes to Total votes ratio for proposal to be vetoed. Default value: 1/3.';
COMMENT ON COLUMN cosmos_gov_params_history.min_initial_deposit_ratio IS 'The ratio representing the proportion of the deposit value that must be paid at proposal submission.';
COMMENT ON COLUMN cosmos_gov_params_history.proposal_cancel_ratio IS 'The cancel ratio which will not be returned back to the depositors when a proposal is cancelled.  Since: cosmos-sdk 0.50';
COMMENT ON COLUMN cosmos_gov_params_history.proposal_cancel_dest IS 'The address which will receive (proposal_cancel_ratio * deposit) proposal deposits. If empty, the (proposal_cancel_ratio * deposit) proposal deposits will be burned.  Since: cosmos-sdk 0.50';
COMMENT ON COLUMN cosmos_gov_params_history.expedited_voting_period IS 'Duration of the voting period of an expedited proposal.  Since: cosmos-sdk 0.50';
COMMENT ON COLUMN cosmos_gov_params_history.expedited_threshold IS 'Minimum proportion of Yes votes for proposal to pass. Default value: 0.67.  Since: cosmos-sdk 0.50';
COMMENT ON COLUMN cosmos_gov_params_history.expedited_min_deposit_amount IS 'Minimum expedited deposit for a proposal to enter voting period.';
COMMENT ON COLUMN cosmos_gov_params_history.expedited_min_deposit_denom IS 'Minimum expedited deposit for a proposal to enter voting period.';
COMMENT ON COLUMN cosmos_gov_params_history.burn_vote_quorum IS 'burn deposits if a proposal does not meet quorum';
COMMENT ON COLUMN cosmos_gov_params_history.burn_proposal_deposit_prevote IS 'burn deposits if the proposal does not enter voting period';
COMMENT ON COLUMN cosmos_gov_params_history.burn_vote_veto IS 'burn deposits if quorum with vote type no_veto is met';
COMMENT ON COLUMN cosmos_gov_params_history.min_deposit_ratio IS 'The ratio representing the proportion of the deposit value minimum that must be met when making a deposit. Default value: 0.01. Meaning that for a chain with a min_deposit of 100stake, a deposit of 1stake would be required.  Since: cosmos-sdk 0.50';

