-- pocket.proof.Params → proof_params_history (first appearance)
CREATE TABLE IF NOT EXISTS proof_params_history (
  proof_request_probability DOUBLE PRECISION NULL,
  proof_requirement_threshold_amount BIGINT NULL,
  proof_requirement_threshold_denom TEXT NULL,
  proof_missing_penalty_amount BIGINT NULL,
  proof_missing_penalty_denom TEXT NULL,
  proof_submission_fee_amount BIGINT NULL,
  proof_submission_fee_denom TEXT NULL,
  block_height BIGINT NOT NULL,
  block_time TIMESTAMPTZ NOT NULL,
  decoded_by_version SMALLINT NOT NULL,
  indexed_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  CONSTRAINT proof_params_history_pk PRIMARY KEY (block_height),
  CONSTRAINT proof_params_history_decoder_fk FOREIGN KEY (decoded_by_version) REFERENCES decoder_version(id)
);
COMMENT ON COLUMN proof_params_history.proof_request_probability IS 'proof_request_probability is the probability of a session requiring a proof if it''s cost (i.e. compute unit consumption) is below the ProofRequirementThreshold.';
COMMENT ON COLUMN proof_params_history.proof_requirement_threshold_amount IS 'proof_requirement_threshold is the session cost (i.e. compute unit consumption) threshold which asserts that a session MUST have a corresponding proof when its cost is equal to or above the threshold. This is in contrast to the this requirement being determined probabilistically via ProofRequestProbability.  TODO_MAINNET: Consider renaming this to `proof_requirement_threshold_upokt`.';
COMMENT ON COLUMN proof_params_history.proof_requirement_threshold_denom IS 'proof_requirement_threshold is the session cost (i.e. compute unit consumption) threshold which asserts that a session MUST have a corresponding proof when its cost is equal to or above the threshold. This is in contrast to the this requirement being determined probabilistically via ProofRequestProbability.  TODO_MAINNET: Consider renaming this to `proof_requirement_threshold_upokt`.';
COMMENT ON COLUMN proof_params_history.proof_missing_penalty_amount IS 'proof_missing_penalty is the number of tokens (uPOKT) which should be slashed from a supplier when a proof is required (either via proof_requirement_threshold or proof_missing_penalty) but is not provided. TODO_MAINNET: Consider renaming this to `proof_missing_penalty_upokt`.';
COMMENT ON COLUMN proof_params_history.proof_missing_penalty_denom IS 'proof_missing_penalty is the number of tokens (uPOKT) which should be slashed from a supplier when a proof is required (either via proof_requirement_threshold or proof_missing_penalty) but is not provided. TODO_MAINNET: Consider renaming this to `proof_missing_penalty_upokt`.';
COMMENT ON COLUMN proof_params_history.proof_submission_fee_amount IS 'proof_submission_fee is the number of tokens (uPOKT) which should be paid by the supplier operator when submitting a proof. This is needed to account for the cost of storing proofs onchain and prevent spamming (i.e. sybil bloat attacks) the network with non-required proofs. TODO_MAINNET: Consider renaming this to `proof_submission_fee_upokt`.';
COMMENT ON COLUMN proof_params_history.proof_submission_fee_denom IS 'proof_submission_fee is the number of tokens (uPOKT) which should be paid by the supplier operator when submitting a proof. This is needed to account for the cost of storing proofs onchain and prevent spamming (i.e. sybil bloat attacks) the network with non-required proofs. TODO_MAINNET: Consider renaming this to `proof_submission_fee_upokt`.';

