-- pocket.shared.Params → shared_params_history (first appearance)
CREATE TABLE IF NOT EXISTS shared_params_history (
  num_blocks_per_session BIGINT NULL,
  grace_period_end_offset_blocks BIGINT NULL,
  claim_window_open_offset_blocks BIGINT NULL,
  claim_window_close_offset_blocks BIGINT NULL,
  proof_window_open_offset_blocks BIGINT NULL,
  proof_window_close_offset_blocks BIGINT NULL,
  supplier_unbonding_period_sessions BIGINT NULL,
  application_unbonding_period_sessions BIGINT NULL,
  compute_units_to_tokens_multiplier BIGINT NULL,
  gateway_unbonding_period_sessions BIGINT NULL,
  block_height BIGINT NOT NULL,
  block_time TIMESTAMPTZ NOT NULL,
  decoded_by_version SMALLINT NOT NULL,
  indexed_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  CONSTRAINT shared_params_history_pk PRIMARY KEY (block_height),
  CONSTRAINT shared_params_history_decoder_fk FOREIGN KEY (decoded_by_version) REFERENCES decoder_version(id)
);
COMMENT ON COLUMN shared_params_history.num_blocks_per_session IS 'num_blocks_per_session is the number of blocks between the session start & end heights.';
COMMENT ON COLUMN shared_params_history.grace_period_end_offset_blocks IS 'grace_period_end_offset_blocks is the number of blocks, after the session end height, during which the supplier can still service payable relays. Suppliers will need to recreate a claim for the previous session (if already created) to get paid for the additional relays.';
COMMENT ON COLUMN shared_params_history.claim_window_open_offset_blocks IS 'claim_window_open_offset_blocks is the number of blocks after the session grace period height, at which the claim window opens.';
COMMENT ON COLUMN shared_params_history.claim_window_close_offset_blocks IS 'claim_window_close_offset_blocks is the number of blocks after the claim window open height, at which the claim window closes.';
COMMENT ON COLUMN shared_params_history.proof_window_open_offset_blocks IS 'proof_window_open_offset_blocks is the number of blocks after the claim window close height, at which the proof window opens.';
COMMENT ON COLUMN shared_params_history.proof_window_close_offset_blocks IS 'proof_window_close_offset_blocks is the number of blocks after the proof window open height, at which the proof window closes.';
COMMENT ON COLUMN shared_params_history.supplier_unbonding_period_sessions IS 'supplier_unbonding_period_sessions is the number of sessions that a supplier must wait after unstaking before their staked assets are moved to their account balance. Onchain business logic requires, and ensures, that the corresponding block count of the unbonding period will exceed the end of any active claim & proof lifecycles.';
COMMENT ON COLUMN shared_params_history.application_unbonding_period_sessions IS 'application_unbonding_period_sessions is the number of sessions that an application must wait after unstaking before their staked assets are moved to their account balance. Onchain business logic requires, and ensures, that the corresponding block count of the application unbonding period will exceed the end of its corresponding proof window close height.';
COMMENT ON COLUMN shared_params_history.compute_units_to_tokens_multiplier IS 'The amount of upokt that a compute unit should translate to when settling a session. DEV_NOTE: This used to be under x/tokenomics but has been moved here to avoid cyclic dependencies.';
COMMENT ON COLUMN shared_params_history.gateway_unbonding_period_sessions IS 'gateway_unbonding_period_sessions is the number of sessions that a gateway must wait after unstaking before their staked assets are moved to its account balance.';

